import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.DdLJaIXX.js";const g=JSON.parse('{"title":"Dogfooding Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dogfooding.md","filePath":"guide/dogfooding.md"}'),n={name:"guide/dogfooding.md"};function o(l,e,r,p,d,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="dogfooding-workflow" tabindex="-1">Dogfooding Workflow <a class="header-anchor" href="#dogfooding-workflow" aria-label="Permalink to &quot;Dogfooding Workflow&quot;">​</a></h1><p>CQ is built with CQ. Every feature ships through the same <code>/pi → /plan → /run → /finish</code> cycle that CQ exposes to users. This guide walks through that cycle from idea to merged commit.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pi (Explore) → /plan (Design + Tasks) → /run (Parallel Workers) → /finish (Verify + Commit)</span></span></code></pre></div><p>Each phase has a clear entry condition and a concrete output. No phase begins until the previous one produces its artifact.</p><table tabindex="0"><thead><tr><th>Phase</th><th>Input</th><th>Output</th><th>Rule</th></tr></thead><tbody><tr><td><code>/pi</code></td><td>Raw idea</td><td><code>.c4/ideas/{slug}.md</code></td><td>No code, no stack decisions</td></tr><tr><td><code>/plan</code></td><td>idea.md</td><td><code>docs/specs/{slug}.md</code> + task queue</td><td>EARS requirements + DoD per task</td></tr><tr><td><code>/run</code></td><td>Task queue</td><td>Implemented, tested code</td><td>Workers in isolated worktrees</td></tr><tr><td><code>/finish</code></td><td>Working code</td><td>Committed, documented change</td><td>Integration review + smoke</td></tr></tbody></table><hr><h2 id="pi-—-idea-exploration" tabindex="-1">/pi — Idea Exploration <a class="header-anchor" href="#pi-—-idea-exploration" aria-label="Permalink to &quot;/pi — Idea Exploration&quot;">​</a></h2><p><code>/pi</code> is a structured thinking mode. It helps you research, debate tradeoffs, and converge on a clear direction before any code is written.</p><p><strong>What it does:</strong></p><ul><li>Searches the knowledge base for prior work on the topic</li><li>Generates competing approaches and forces explicit tradeoff analysis</li><li>Records the session as a knowledge entry so future sessions can build on it</li><li>Produces a concise idea document in <code>.c4/ideas/</code></li></ul><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pi &quot;improve claim extraction quality&quot;</span></span></code></pre></div><p>After the session, <code>.c4/ideas/improve-claim-extraction-quality.md</code> contains:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Problem</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Claim extraction misses ~30% of implicit dependencies in large files.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Options Considered</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Increase chunk overlap (fast, marginal gain)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Tree-sitter AST pass before LLM extraction (accurate, slower)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Two-pass: coarse LLM → symbol resolver (balanced)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Decision</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Option 3. Coarse pass uses cheap model. Symbol resolver is deterministic.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Risks</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Symbol resolver adds ~120ms per file on cold cache</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Needs language-server integration (Go, Python, TS only initially)</span></span></code></pre></div><p><strong>Key rule:</strong> <code>/pi</code> produces thinking, not code. No file paths, no library versions, no implementation details. If you catch yourself writing code during <code>/pi</code>, stop — that belongs in <code>/plan</code> or <code>/run</code>.</p><hr><h2 id="plan-—-design-task-creation" tabindex="-1">/plan — Design + Task Creation <a class="header-anchor" href="#plan-—-design-task-creation" aria-label="Permalink to &quot;/plan — Design + Task Creation&quot;">​</a></h2><p><code>/plan</code> translates the idea into a concrete implementation plan with EARS requirements, architecture decisions, and a dependency-ordered task graph.</p><p><strong>What it produces:</strong></p><ul><li><code>docs/specs/{slug}.md</code> — full specification document</li><li>Tasks added to the queue, each with a DoD checklist and test strategy</li><li>Architecture Decision Records (DEC-XXX) for non-obvious choices</li></ul><p><strong>Spec structure:</strong></p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Requirements (EARS)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WHEN a file is submitted, the system SHALL extract all explicit and implicit claims</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WHERE a symbol cannot be resolved, the system SHALL record a partial claim with </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`unresolved: true\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Architecture</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEC-001: Two-pass extraction</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Rationale: Coarse LLM pass is cheap; resolver pass is deterministic and cacheable.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Alternative rejected: Single-pass AST required language-server per language (high complexity).</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Tasks</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] T-001: Add tree-sitter parser stub (DoD: parses Go + Python + TS, unit tests pass)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] T-002: Coarse LLM extraction (DoD: handles 10k token files, extracts &gt;90% explicit claims)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] T-003: Symbol resolver integration (DoD: resolves local symbols, E2E test passes)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] T-004: Wire two-pass pipeline (DoD: integration test, smoke test against real codebase)</span></span></code></pre></div><p><strong>Running /plan:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plan &quot;improve-claim-extraction-quality&quot;</span></span></code></pre></div><p>CQ reads the idea file, interviews you on ambiguous requirements (if needed), and writes the spec. Tasks are added to the queue automatically.</p><p>To inspect the resulting queue:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Queue: 4 tasks (4 pending, 0 in-progress, 0 done)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>T-001  Add tree-sitter parser stub          [pending]</span></span>
<span class="line"><span>T-002  Coarse LLM extraction               [pending]  ← T-001</span></span>
<span class="line"><span>T-003  Symbol resolver integration         [pending]  ← T-001</span></span>
<span class="line"><span>T-004  Wire two-pass pipeline              [pending]  ← T-002, T-003</span></span></code></pre></div><hr><h2 id="run-—-parallel-execution" tabindex="-1">/run — Parallel Execution <a class="header-anchor" href="#run-—-parallel-execution" aria-label="Permalink to &quot;/run — Parallel Execution&quot;">​</a></h2><p><code>/run</code> spawns worker agents in isolated git worktrees. Each worker claims one task, implements it, validates it, and submits. Workers run in parallel whenever the task graph allows.</p><p><strong>What happens under the hood:</strong></p><ol><li>CQ reads the task graph and identifies tasks with no unmet dependencies</li><li>For each ready task, a worker agent is spawned in <code>.claude/worktrees/{task-id}/</code></li><li>The worker implements the task following TDD: write failing test → implement → pass</li><li>On completion, the worker calls <code>/finish</code> internally to commit and merge back</li><li>CQ re-evaluates the graph and spawns new workers for newly unblocked tasks</li><li>Loop continues until the queue is empty</li></ol><p><strong>Starting /run:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/run</span></span></code></pre></div><p>Or target a specific task:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/run T-002</span></span></code></pre></div><p><strong>Worker output (example):</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[T-001] Spawning worker in worktrees/T-001...</span></span>
<span class="line"><span>[T-002] Waiting for T-001...</span></span>
<span class="line"><span>[T-003] Waiting for T-001...</span></span>
<span class="line"><span>[T-001] PASS: tree_sitter_test.go (3 tests)</span></span>
<span class="line"><span>[T-001] Merged. Unblocking T-002, T-003.</span></span>
<span class="line"><span>[T-002] Spawning worker in worktrees/T-002...</span></span>
<span class="line"><span>[T-003] Spawning worker in worktrees/T-003...</span></span>
<span class="line"><span>[T-002] PASS: extraction_test.go (12 tests)</span></span>
<span class="line"><span>[T-003] PASS: resolver_test.go (8 tests)</span></span>
<span class="line"><span>[T-002] Merged. T-004 still waiting for T-003.</span></span>
<span class="line"><span>[T-003] Merged. Unblocking T-004.</span></span>
<span class="line"><span>[T-004] Spawning worker in worktrees/T-004...</span></span>
<span class="line"><span>[T-004] PASS: integration_test.go (5 tests)</span></span>
<span class="line"><span>[T-004] Merged. Queue empty.</span></span></code></pre></div><p><strong>Worker limit:</strong> CQ enforces a maximum of 5 concurrent background workers. If all 5 slots are occupied, new workers queue until a slot opens. This prevents system overload on developer machines.</p><p><strong>Contract tasks (TDD pipeline):</strong></p><p>Tasks with a <code>test_strategy: contract</code> annotation follow a stricter pipeline:</p><ol><li>Generate the failing test from the spec&#39;s DoD</li><li>Verify it fails for the right reason (not a compile error)</li><li>Implement until the test passes</li><li>No submission until <code>go test</code> (or equivalent) is green</li></ol><hr><h2 id="finish-—-verify-commit" tabindex="-1">/finish — Verify + Commit <a class="header-anchor" href="#finish-—-verify-commit" aria-label="Permalink to &quot;/finish — Verify + Commit&quot;">​</a></h2><p><code>/finish</code> is the integration gate. It runs after all tasks are merged into the main branch, before the change is considered done.</p><p><strong>Steps:</strong></p><h3 id="_1-integration-review" tabindex="-1">1. Integration Review <a class="header-anchor" href="#_1-integration-review" aria-label="Permalink to &quot;1. Integration Review&quot;">​</a></h3><p>CQ scans all changes introduced since the plan was created and checks:</p><ul><li>Does every task&#39;s DoD appear satisfied?</li><li>Are there any obvious gaps between the spec requirements and the implementation?</li><li>Is the change set coherent (no unrelated edits)?</li></ul><h3 id="_2-build-test" tabindex="-1">2. Build + Test <a class="header-anchor" href="#_2-build-test" aria-label="Permalink to &quot;2. Build + Test&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./...</span></span></code></pre></div><p>Build or vet failure blocks <code>/finish</code>. Tests with <code>// +build integration</code> tags are run if the <code>INTEGRATION</code> environment variable is set.</p><h3 id="_3-wire-smoke-l2" tabindex="-1">3. Wire Smoke (L2) <a class="header-anchor" href="#_3-wire-smoke-l2" aria-label="Permalink to &quot;3. Wire Smoke (L2)&quot;">​</a></h3><p>Four smoke scripts run against the local binary:</p><table tabindex="0"><thead><tr><th>Script</th><th>What it checks</th></tr></thead><tbody><tr><td><code>wire-smoke.sh</code></td><td>MCP tool registration, all expected tools present</td></tr><tr><td><code>cf-smoke.sh</code></td><td>Cloudflare Worker endpoints respond correctly</td></tr><tr><td><code>edge-smoke.sh</code></td><td>Edge function schema matches local types</td></tr><tr><td><code>migration-lint.sh</code></td><td>SQL migrations are idempotent and reversible</td></tr></tbody></table><p>Any script exiting non-zero blocks <code>/finish</code> and prints a diff of what changed vs. what was expected.</p><h3 id="_4-documentation-update" tabindex="-1">4. Documentation Update <a class="header-anchor" href="#_4-documentation-update" aria-label="Permalink to &quot;4. Documentation Update&quot;">​</a></h3><p><code>/finish</code> checks whether the change affects:</p><ul><li>Public API or CLI flags → updates <code>docs/</code> accordingly</li><li>A behavior that differs from current documentation → flags it for manual review</li></ul><h3 id="_5-knowledge-recording" tabindex="-1">5. Knowledge Recording <a class="header-anchor" href="#_5-knowledge-recording" aria-label="Permalink to &quot;5. Knowledge Recording&quot;">​</a></h3><p>Key decisions and lessons from this cycle are recorded to the knowledge base:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cq_knowledge_record: &quot;Two-pass claim extraction: coarse LLM + symbol resolver&quot;</span></span>
<span class="line"><span>  tags: [claim-extraction, architecture, DEC-001]</span></span></code></pre></div><p>Future <code>/pi</code> sessions on related topics will surface this automatically.</p><h3 id="_6-git-commit" tabindex="-1">6. Git Commit <a class="header-anchor" href="#_6-git-commit" aria-label="Permalink to &quot;6. Git Commit&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(extract): two-pass claim extraction with symbol resolver</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Adds tree-sitter-based symbol resolution as a second pass after</span></span>
<span class="line"><span>coarse LLM extraction. Reduces missed implicit claims from ~30% to</span></span>
<span class="line"><span>~4% on the internal test corpus.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DEC-001: rejected single-pass AST approach (complexity, per-language LS required).</span></span></code></pre></div><p>Conventional Commits format is enforced. Subject line under 72 characters. Body explains &quot;why&quot;, not &quot;what&quot;.</p><hr><h2 id="team-areas-and-first-tasks" tabindex="-1">Team Areas and First Tasks <a class="header-anchor" href="#team-areas-and-first-tasks" aria-label="Permalink to &quot;Team Areas and First Tasks&quot;">​</a></h2><p>New contributors can pick any area and start with a <code>/pi</code> seed. The table below shows what experience to expect.</p><table tabindex="0"><thead><tr><th>Area</th><th>/pi Seed</th><th>Expected Experience</th></tr></thead><tbody><tr><td><strong>Backend</strong> (Go)</td><td><code>/pi &quot;reduce p99 latency on knowledge_search&quot;</code></td><td>Work through profiling → hypothesis → targeted change cycle. Familiar if you&#39;ve done Go pprof before.</td></tr><tr><td><strong>Frontend</strong> (TypeScript)</td><td><code>/pi &quot;improve task status visibility in the TUI&quot;</code></td><td>Terminal UI work with Bubble Tea. Constraints are tight (80-char width, no color assumptions).</td></tr><tr><td><strong>Install / CLI</strong></td><td><code>/pi &quot;make cq init idempotent on re-run&quot;</code></td><td>Shell + Go flag parsing. High-impact, low surface area. Good first contribution.</td></tr><tr><td><strong>Harness / Testing</strong></td><td><code>/pi &quot;add contract test for cq_knowledge_record schema&quot;</code></td><td>Understand the MCP schema contract system. No domain knowledge required — spec is the source of truth.</td></tr></tbody></table><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><h3 id="auto-implementation-mode" tabindex="-1">Auto-implementation mode <a class="header-anchor" href="#auto-implementation-mode" aria-label="Permalink to &quot;Auto-implementation mode&quot;">​</a></h3><p>Chaining phases is supported:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pi &quot;add rate limiting to hub job submissions&quot; --plan --run</span></span></code></pre></div><p>This runs <code>/pi</code> → <code>/plan</code> → <code>/run</code> sequentially without stopping for confirmation. Use when the idea is clear and you want CQ to drive. You can interrupt at any phase with Ctrl-C.</p><h3 id="worker-count" tabindex="-1">Worker count <a class="header-anchor" href="#worker-count" aria-label="Permalink to &quot;Worker count&quot;">​</a></h3><p>The default is 3 concurrent workers. Override per session:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/run --workers 5</span></span></code></pre></div><p>The hard cap is 5. Setting <code>--workers</code> above 5 is silently clamped.</p><h3 id="knowledge-accumulation" tabindex="-1">Knowledge accumulation <a class="header-anchor" href="#knowledge-accumulation" aria-label="Permalink to &quot;Knowledge accumulation&quot;">​</a></h3><p>Every <code>/pi</code> session records insights to the knowledge base under the <code>dogfooding</code> tag. Over time, CQ builds a map of which ideas led to which specs, which specs led to which bugs, and which bugs surfaced which design gaps. This loop is the primary source of CQ&#39;s self-improvement signal.</p><p>To query it:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;What have we learned about claim extraction?&quot;</span></span></code></pre></div><p>CQ calls <code>cq_knowledge_search</code> and returns ranked entries across all past sessions.</p>`,87)])])}const u=s(n,[["render",o]]);export{g as __pageData,u as default};
